const t=document.getElementById("nav-hamburger"),a=document.getElementById("nav-mobile");t.addEventListener("click",()=>{const e=a.classList.toggle("open");t.setAttribute("aria-expanded",String(e)),t.setAttribute("aria-label",e?"Close menu":"Open menu"),a.setAttribute("aria-hidden",String(!e))});a.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{a.classList.remove("open"),t.setAttribute("aria-expanded","false"),t.setAttribute("aria-label","Open menu"),a.setAttribute("aria-hidden","true")})});document.addEventListener("click",e=>{const n=document.querySelector(".nav-wrap");n&&!n.contains(e.target)&&(a.classList.remove("open"),t.setAttribute("aria-expanded","false"),t.setAttribute("aria-label","Open menu"),a.setAttribute("aria-hidden","true"))});
